&reftitle.description;
stringrtrim stringstring stringcharacters" \n\r\t\v\x00"
Esta función devuelve un string con los espacios en blanco retirados del final de string.
Sin el segundo parámetro, rtrim retirará estos caracteres:
&strings.stripped.characters;

&reftitle.parameters;


  string


    El string de entrada.




  characters

   &strings.parameter.characters.optional;

  &reftitle.examples;



    Ejemplo de uso de rtrim


<?php

$text = "\t\tEstas son algunas palabras :) ...  ";
$binary = "\x09String de ejemplo\x0A";
$hello  = "Hola Mundo";
var_dump($text, $binary, $hello);

print "\n";

$trimmed = rtrim($text);
var_dump($trimmed);

$trimmed = rtrim($text, " \t.");
var_dump($trimmed);

$trimmed = rtrim($hello, "Hdoe");
var_dump($trimmed);

// Recorta los caracteres de control ASCII al final de $binary
// (desde 0 hasta 31 inclusive)
$clean = rtrim($binary, "\x00..\x1F");
var_dump($clean);

?>


    &example.outputs;


string(37) "        Estas son algunas palabras :) ...  "
string(19) "    String de ejemplo
"
string(10) "Hola Mundo"

string(35) "        Estas son algunas palabras :) ..."
string(31) "        Estas son algunas palabras :)"
string(8) "Hola Mun"
string(18) "    String de ejemplo"
